pub const TX_TYPE_SCHEDULED: u8 = 0x10;
pub const TX_TYPE_ASYNC_COMMITMENT: u8 = 0x11;
pub const TX_TYPE_ASYNC_SETTLEMENT: u8 = 0x12;

#[inline]
pub fn is_system_transaction(tx_type: u8) -> bool {
    matches!(tx_type, TX_TYPE_SCHEDULED | TX_TYPE_ASYNC_COMMITMENT | TX_TYPE_ASYNC_SETTLEMENT)
}

const TX_BASE_COST: u64 = 21_000;
const ZERO_BYTE_COST: u64 = 4;
const NON_ZERO_BYTE_COST: u64 = 16;

#[inline]
pub fn calculate_calldata_gas(input: &[u8]) -> Result<u64, &'static str> {
    let calldata_cost: u64 = input
        .iter()
        .map(|&byte| if byte == 0 { ZERO_BYTE_COST } else { NON_ZERO_BYTE_COST })
        .fold(0u64, |acc, cost| acc.saturating_add(cost));

    TX_BASE_COST.checked_add(calldata_cost).ok_or("Calldata gas calculation overflow")
}

pub fn effective_gas_limit_for_block(
    tx_type: u8,
    input: &[u8],
    gas_limit: u64,
) -> Result<u64, &'static str> {
    if tx_type == TX_TYPE_ASYNC_COMMITMENT {
        Ok(0)
    } else if is_system_transaction(tx_type) {
        calculate_calldata_gas(input)
    } else {
        Ok(gas_limit)
    }
}

